import { useSolanaWallet } from "@/lib/solana-wallet";

async function persistEmployerProfile(payload: {
  ownerAddress: string;
  employerName: string;
  position: string;
  companyName: string;
  industry: string;
  employeeCountRange: string;
  escrowContract?: string;
}) {
