export default function EmployerPage() {
  const { address, connected, signAndSendTransaction } = useSolanaWallet();
  const {
    company,
    setCompany,
    employees,
    payrollRuns,
    auditors,
    commitmentCount,
    poolBalanceFormatted,
    isLoadingProfile,
    addEmployee,
    refreshOnChainState,
  } = useCivitas();
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [setupState, setSetupState] = useState<string | null>(null);
  const [setupError, setSetupError] = useState<string | null>(null);
  const [isFinalizingSetup, setIsFinalizingSetup] = useState(false);
  const [employeeTag, setEmployeeTag] = useState("");
  const [employeeName, setEmployeeName] = useState("");
  const [employeeSalary, setEmployeeSalary] = useState("");
  const [employeeFormState, setEmployeeFormState] = useState<"idle" | "saving" | "success" | "error">("idle");
  const [employeeFormMessage, setEmployeeFormMessage] = useState<string | null>(null);

  const {
    status: vaultStatus,
    vaultPda,
    error: vaultError,
    initialize,
  } = useInitializeVault(address, connected ? signAndSendTransaction : null);

  useEffect(() => {
    if (connected && address && !company && !isLoadingProfile) {
      setShowOnboarding(true);
      return;
    }

    if (!connected) {
      setShowOnboarding(false);
    }
  }, [address, company, connected, isLoadingProfile]);

  const syncProfileWithVault = useCallback(
    async (profile: EmployerProfileData & { companyId: string }, escrowContract: string) => {
      if (!address) return;

      await persistEmployerProfile({
        ownerAddress: address,
        employerName: profile.employerName,
        position: profile.position,
        companyName: profile.companyName,
        industry: profile.industry,
        employeeCountRange: profile.employeeCountRange,
        escrowContract,
      });

      setCompany({
        companyId: profile.companyId,
        name: profile.companyName,
        ownerAddress: address,
        escrowContract,
        employerName: profile.employerName,
        position: profile.position,
        industry: profile.industry,
        employeeCountRange: profile.employeeCountRange,
      } as CompanyProfile);
    },
    [address, setCompany],
  );

  const handleCompleteOnboarding = useCallback(
    async (profile: EmployerProfileData & { companyId: string }) => {
      if (!address) return;

      setIsFinalizingSetup(true);
      setSetupError(null);

      try {
        let escrowContract = vaultPda || company?.escrowContract || "";

        if (vaultStatus === "ready" || vaultStatus === "error") {
          setSetupState("Initializing the employer treasury vault on Solana...");
          await initialize();
          escrowContract = vaultPda || escrowContract;
        } else if (vaultStatus === "exists" || vaultStatus === "success") {
          setSetupState("Linking the existing treasury vault...");
          escrowContract = vaultPda || escrowContract;
        } else if (vaultStatus === "checking") {
          setSetupState("Checking treasury vault status...");
        }

        if (!escrowContract) {
          throw new Error("Treasury vault address could not be resolved.");
        }

        setSetupState("Saving employer profile to NilDB...");
        await syncProfileWithVault(profile, escrowContract);
        await refreshOnChainState();
        setShowOnboarding(false);
        setSetupState("Employer onboarding complete.");
      } catch (error) {
        const message = error instanceof Error ? error.message : "Failed to finish employer setup";
        setSetupError(message);
      } finally {
        setIsFinalizingSetup(false);
      }
    },
    [address, company?.escrowContract, initialize, refreshOnChainState, syncProfileWithVault, vaultPda, vaultStatus],
  );

  const handleAddEmployee = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      if (!address) {
        setEmployeeFormState("error");
        setEmployeeFormMessage("Connect a Solana wallet before adding employees.");
        return;
      }

      const normalizedTag = employeeTag.trim();
      if (!normalizedTag) {
        setEmployeeFormState("error");
        setEmployeeFormMessage("Employee tag is required.");
        return;
      }

      setEmployeeFormState("saving");
      setEmployeeFormMessage(null);

      try {
        const res = await fetch("/api/employer/employees", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            ownerAddress: address,
            employeeTag: normalizedTag,
            employeeName: employeeName.trim(),
            salaryAmount: employeeSalary.trim() || "0",
            salaryCurrency: "USDC",
          }),
        });

        const data = await res.json().catch(() => ({}));
        if (!res.ok) {
          throw new Error(data?.error || "Failed to add employee");
        }

        const saved = data?.employee || {};
        await addEmployee({
          employeeTag: saved.employee_tag || normalizedTag,
          name: saved.employee_name || employeeName.trim() || "Unnamed contributor",
          salaryAmount: saved.salary_amount || employeeSalary.trim() || "0",
          salaryCurrency: saved.salary_currency || "USDC",
          addedAt: saved.created_at || new Date().toISOString(),
        });

        setEmployeeTag("");
        setEmployeeName("");
        setEmployeeSalary("");
        setEmployeeFormState("success");
        setEmployeeFormMessage("Employee added to the payroll roster.");
      } catch (error) {
        setEmployeeFormState("error");
        setEmployeeFormMessage(error instanceof Error ? error.message : "Failed to add employee");
      }
    },
    [addEmployee, address, employeeName, employeeSalary, employeeTag],
  );

  useEffect(() => {
    if (!address || !company || company.escrowContract || !vaultPda) return;
    if (vaultStatus !== "exists" && vaultStatus !== "success") return;

    const backfillEscrow = async () => {
      try {
        await persistEmployerProfile({
          ownerAddress: address,
          employerName: company.employerName || "",
          position: company.position || "",
          companyName: company.name,
          industry: company.industry || "",
